"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

type MatrixPreset = "idle" | "thinking" | "speaking" | "off";

interface MatrixProps
  extends
    Omit<React.ComponentProps<"div">, "children">,
    VariantProps<typeof matrixVariants> {
  /** Number of columns in the dot grid. Default: 12 */
  columns?: number;
  /** Number of rows in the dot grid. Default: 5 */
  rows?: number;
  /** Dot radius in pixels. Default: 3 */
  dotSize?: number;
  /** Gap between dots in pixels. Default: 6 */
  gap?: number;
  /** Animation preset. Default: "idle" */
  preset?: MatrixPreset;
  /** Custom dot opacities (columns * rows). Overrides preset animation. */
  values?: number[];
  /** Dot color. Default: currentColor */
  dotColor?: string;
}

// =============================================================================
// VARIANTS
// =============================================================================

const matrixVariants = cva("inline-flex items-center justify-center", {
  variants: {
    size: {
      sm: "p-2",
      md: "p-3",
      lg: "p-4",
    },
  },
  defaultVariants: {
    size: "md",
  },
});

// =============================================================================
// ANIMATION PRESETS
// =============================================================================

function useMatrixAnimation(
  preset: MatrixPreset,
  columns: number,
  rows: number,
  values?: number[]
): number[] {
  const [opacities, setOpacities] = React.useState<number[]>(
    () => values ?? new Array(columns * rows).fill(preset === "off" ? 0.1 : 0.2)
  );

  React.useEffect(() => {
    if (values) {
      setOpacities(values);
      return;
    }

    if (preset === "off") {
      setOpacities(new Array(columns * rows).fill(0.08));
      return;
    }

    let frame: number;
    let t = 0;
    const total = columns * rows;

    const animate = () => {
      t += 0.04;
      const newOpacities = new Array(total);

      for (let i = 0; i < total; i++) {
        const col = i % columns;
        const row = Math.floor(i / columns);

        let opacity: number;

        switch (preset) {
          case "idle": {
            const wave = Math.sin(t * 0.8 + col * 0.4 + row * 0.3) * 0.15 + 0.2;
            opacity = Math.max(0.05, Math.min(0.4, wave));
            break;
          }
          case "thinking": {
            const wave =
              Math.sin(t * 2.5 + col * 0.6) * 0.3 +
              Math.cos(t * 1.8 + row * 0.8) * 0.2 +
              0.5;
            opacity = Math.max(0.05, Math.min(1, wave));
            break;
          }
          case "speaking": {
            const wave =
              Math.sin(t * 3 + col * 1.2) * 0.35 +
              Math.sin(t * 1.5 + row * 0.6 + col * 0.3) * 0.25 +
              0.55;
            opacity = Math.max(0.1, Math.min(1, wave));
            break;
          }
          default:
            opacity = 0.08;
        }

        newOpacities[i] = opacity;
      }

      setOpacities(newOpacities);
      frame = requestAnimationFrame(animate);
    };

    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [preset, columns, rows, values]);

  return opacities;
}

// =============================================================================
// COMPONENT
// =============================================================================

function Matrix({
  columns = 12,
  rows = 5,
  dotSize = 3,
  gap = 6,
  preset = "idle",
  values,
  dotColor,
  size,
  className,
  ...props
}: MatrixProps) {
  const opacities = useMatrixAnimation(preset, columns, rows, values);

  const svgWidth = columns * (dotSize * 2 + gap) - gap;
  const svgHeight = rows * (dotSize * 2 + gap) - gap;

  return (
    <div
      data-slot="matrix"
      data-preset={preset}
      className={cn("text-primary", matrixVariants({ size }), className)}
      role="img"
      aria-label={`Matrix display - ${preset}`}
      {...props}
    >
      <svg
        width={svgWidth}
        height={svgHeight}
        viewBox={`0 0 ${svgWidth} ${svgHeight}`}
        fill={dotColor || "currentColor"}
      >
        {opacities.map((opacity, i) => {
          const col = i % columns;
          const row = Math.floor(i / columns);
          const cx = col * (dotSize * 2 + gap) + dotSize;
          const cy = row * (dotSize * 2 + gap) + dotSize;

          return (
            <circle key={i} cx={cx} cy={cy} r={dotSize} opacity={opacity} />
          );
        })}
      </svg>
    </div>
  );
}

Matrix.displayName = "Matrix";

export { Matrix, matrixVariants };
export type { MatrixProps, MatrixPreset };
